namespace sv_c3c72caa98bd44efbd3caaee59df8fc7.Models;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);

public record NotificationPrefs(
    bool EmailNotifications,
    bool PushNotifications,
    bool WeeklyDigest,
    List<string> MutedChannels);

public record SecuritySettings(
    bool TwoFactorEnabled,
    DateTime? LastPasswordChange,
    List<ActiveSession> Sessions);

public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);

public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

using sv_c3c72caa98bd44efbd3caaee59df8fc7.Models;

namespace sv_c3c72caa98bd44efbd3caaee59df8fc7.Services;

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

using sv_c3c72caa98bd44efbd3caaee59df8fc7.Models;

namespace sv_c3c72caa98bd44efbd3caaee59df8fc7.Services;

public class InMemorySettingsService : ISettingsService
{
    private UserProfile _profile = new(
        "Jane Doe",
        "jane.doe@example.com",
        "https://i.pravatar.cc/150?u=jane",
        "Full-stack developer passionate about clean code and good UX.");

    private NotificationPrefs _notificationPrefs = new(
        EmailNotifications: true,
        PushNotifications: true,
        WeeklyDigest: false,
        MutedChannels: ["marketing", "random"]);

    private SecuritySettings _security = new(
        TwoFactorEnabled: false,
        LastPasswordChange: DateTime.UtcNow.AddDays(-45),
        Sessions:
        [
            new("sess-1", "Chrome on Windows", "New York, US", DateTime.UtcNow.AddMinutes(-5)),
            new("sess-2", "Safari on iPhone", "New York, US", DateTime.UtcNow.AddHours(-3)),
            new("sess-3", "Firefox on Linux", "London, UK", DateTime.UtcNow.AddDays(-2)),
        ]);

    private AppearanceSettings _appearance = new("Light", "Medium", "English", false);

    // Simulate a short async delay for realism
    private static async Task SimulateDelay() => await Task.Delay(250);

    public async Task<UserProfile> GetProfileAsync()
    {
        await SimulateDelay();
        return _profile;
    }

    public async Task SaveProfileAsync(UserProfile profile)
    {
        await SimulateDelay();
        _profile = profile;
    }

    public async Task<NotificationPrefs> GetNotificationPrefsAsync()
    {
        await SimulateDelay();
        return _notificationPrefs;
    }

    public async Task SaveNotificationPrefsAsync(NotificationPrefs prefs)
    {
        await SimulateDelay();
        _notificationPrefs = prefs;
    }

    public async Task<SecuritySettings> GetSecuritySettingsAsync()
    {
        await SimulateDelay();
        return _security;
    }

    public async Task ChangePasswordAsync(string currentPassword, string newPassword)
    {
        await SimulateDelay();
        if (string.IsNullOrWhiteSpace(currentPassword))
            throw new InvalidOperationException("Current password is required.");
        if (newPassword.Length < 8)
            throw new InvalidOperationException("New password must be at least 8 characters.");

        _security = _security with { LastPasswordChange = DateTime.UtcNow };
    }

    public async Task RevokeSessionAsync(string sessionId)
    {
        await SimulateDelay();
        var updated = _security.Sessions.Where(s => s.Id != sessionId).ToList();
        _security = _security with { Sessions = updated };
    }

    public async Task<AppearanceSettings> GetAppearanceAsync()
    {
        await SimulateDelay();
        return _appearance;
    }

    public async Task SaveAppearanceAsync(AppearanceSettings settings)
    {
        await SimulateDelay();
        _appearance = settings;
    }
}

