toolArgs.file_text:
@page "/settings"
@using sv_c3c72caa98bd44efbd3caaee59df8fc7.Models
@using sv_c3c72caa98bd44efbd3caaee59df8fc7.Services
@rendermode InteractiveServer
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    @* ───── Left sidebar navigation ───── *@
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        @foreach (var section in _sections)
        {
            <button class="sidebar-btn @(ActiveSection == section.Key ? "active" : "")"
                    @onclick="() => SetActiveSection(section.Key)">
                <span class="sidebar-icon">@section.Value.Icon</span>
                @section.Value.Label
            </button>
        }
    </nav>

    @* ───── Main content area ───── *@
    <div class="settings-content">
        @if (_loading)
        {
            <div class="text-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading…</span>
                </div>
            </div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfile()
                    break;
                case "notifications":
                    @RenderNotifications()
                    break;
                case "security":
                    @RenderSecurity()
                    break;
                case "appearance":
                    @RenderAppearance()
                    break;
            }
        }

        @* ───── Toast message ───── *@
        @if (!string.IsNullOrEmpty(_toastMessage))
        {
            <div class="settings-toast @(_toastIsError ? "toast-error" : "toast-success")">
                @_toastMessage
            </div>
        }
    </div>
</div>

@* ───── Revoke-session confirmation modal ───── *@
@if (_showRevokeConfirm)
{
    <div class="modal-backdrop show" @onclick="CancelRevoke"></div>
    <div class="modal d-block" tabindex="-1">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@_revokeTarget?.Device</strong> (@_revokeTarget?.Location)?</p>
                    <p class="text-muted mb-0">This will immediately sign out that device.</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                    <button class="btn btn-danger" @onclick="ConfirmRevoke" disabled="@_saving">
                        @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Revoke
                    </button>
                </div>
            </div>
        </div>
    </div>
}

@* ═══════════════════════════════════════════════════════════════
   Section render fragments
   ═══════════════════════════════════════════════════════════════ *@

@{
    RenderFragment RenderProfile() =>
        @<section>
            <h4 class="section-heading">Profile</h4>
            <div class="card settings-card">
                <div class="card-body">
                    <div class="avatar-area mb-4">
                        <img src="@_profileAvatarUrl" alt="Avatar" class="avatar-img" />
                        <span class="text-muted small">@_profileAvatarUrl</span>
                    </div>

                    <div class="mb-3">
                        <label class="form-label">Display Name</label>
                        <input class="form-control" @bind="_profileDisplayName" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Email</label>
                        <input type="email" class="form-control" @bind="_profileEmail" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Bio</label>
                        <textarea class="form-control" rows="3" @bind="_profileBio"></textarea>
                    </div>

                    <div class="d-flex gap-2">
                        <button class="btn btn-primary" @onclick="SaveProfile" disabled="@_saving">
                            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                            Save Changes
                        </button>
                        <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges" disabled="@_saving">
                            Discard Changes
                        </button>
                    </div>
                </div>
            </div>
        </section>;

    RenderFragment RenderNotifications() =>
        @<section>
            <h4 class="section-heading">Notifications</h4>
            <div class="card settings-card">
                <div class="card-body">
                    <div class="form-check form-switch mb-3">
                        <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_notifEmail" />
                        <label class="form-check-label" for="emailNotif">Email Notifications</label>
                    </div>
                    <div class="form-check form-switch mb-3">
                        <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_notifPush" />
                        <label class="form-check-label" for="pushNotif">Push Notifications</label>
                    </div>
                    <div class="form-check form-switch mb-4">
                        <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_notifWeekly" />
                        <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
                    </div>

                    <h6>Muted Channels</h6>
                    <div class="channel-list mb-4">
                        @foreach (var channel in _allChannels)
                        {
                            var ch = channel;
                            <div class="form-check">
                                <input class="form-check-input" type="checkbox" id="ch-@ch"
                                       checked="@_mutedChannels.Contains(ch)"
                                       @onchange="(e) => ToggleMuteChannel(ch, (bool)(e.Value ?? false))" />
                                <label class="form-check-label" for="ch-@ch">#@ch</label>
                            </div>
                        }
                    </div>

                    <button class="btn btn-primary" @onclick="SaveNotifications" disabled="@_saving">
                        @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Save Preferences
                    </button>
                </div>
            </div>
        </section>;

    RenderFragment RenderSecurity() =>
        @<section>
            <h4 class="section-heading">Security</h4>

            @* ── Change Password panel ── *@
            <div class="card settings-card mb-3">
                <div class="card-header d-flex justify-content-between align-items-center"
                     style="cursor:pointer" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                    <span>Change Password</span>
                    <span>@(_passwordPanelOpen ? "▲" : "▼")</span>
                </div>
                @if (_passwordPanelOpen)
                {
                    <div class="card-body">
                        <div class="mb-3">
                            <label class="form-label">Current Password</label>
                            <input type="password" class="form-control" @bind="_currentPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">New Password</label>
                            <input type="password" class="form-control" @bind="_newPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Confirm New Password</label>
                            <input type="password" class="form-control" @bind="_confirmPassword" />
                        </div>
                        <button class="btn btn-primary" @onclick="UpdatePassword" disabled="@_saving">
                            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                            Update Password
                        </button>
                    </div>
                }
            </div>

            @* ── Two-Factor Authentication ── *@
            <div class="card settings-card mb-3">
                <div class="card-body d-flex align-items-center justify-content-between">
                    <div>
                        <strong>Two-Factor Authentication</strong>
                        <span class="badge ms-2 @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                        @if (_securitySettings?.LastPasswordChange is not null)
                        {
                            <div class="text-muted small mt-1">
                                Last password change: @_securitySettings.LastPasswordChange.Value.ToString("MMM dd, yyyy")
                            </div>
                        }
                    </div>
                    <div class="form-check form-switch mb-0">
                        <input class="form-check-input" type="checkbox" @bind="_twoFactorEnabled" />
                    </div>
                </div>
            </div>

            @* ── Active Sessions ── *@
            <div class="card settings-card">
                <div class="card-header">Active Sessions</div>
                <div class="card-body p-0">
                    <div class="table-responsive">
                        <table class="table table-hover mb-0">
                            <thead>
                                <tr>
                                    <th>Device</th>
                                    <th>Location</th>
                                    <th>Last Active</th>
                                    <th></th>
                                </tr>
                            </thead>
                            <tbody>
                                @if (_sessions is not null)
                                {
                                    @foreach (var session in _sessions)
                                    {
                                        <tr>
                                            <td>@session.Device</td>
                                            <td>@session.Location</td>
                                            <td>@FormatLastActive(session.LastActive)</td>
                                            <td class="text-end">
                                                @if (session.Id != _currentSessionId)
                                                {
                                                    <button class="btn btn-sm btn-outline-danger"
                                                            @onclick="() => RequestRevoke(session)">
                                                        Revoke
                                                    </button>
                                                }
                                                else
                                                {
                                                    <span class="badge bg-info">Current</span>
                                                }
                                            </td>
                                        </tr>
                                    }
                                }
                            </tbody>
                        </table>
                    </div>
                </div>
            </div>
        </section>;

    RenderFragment RenderAppearance() =>
        @<section>
            <h4 class="section-heading">Appearance</h4>
            <div class="card settings-card mb-3">
                <div class="card-body">
                    <div class="mb-4">
                        <label class="form-label fw-semibold">Theme</label>
                        <div class="d-flex gap-3">
                            @foreach (var theme in new[] { "Light", "Dark", "System" })
                            {
                                var t = theme;
                                <div class="form-check">
                                    <input class="form-check-input" type="radio" name="theme" id="theme-@t"
                                           value="@t" checked="@(_appTheme == t)"
                                           @onchange="() => _appTheme = t" />
                                    <label class="form-check-label" for="theme-@t">@t</label>
                                </div>
                            }
                        </div>
                    </div>

                    <div class="mb-4">
                        <label class="form-label fw-semibold">Font Size</label>
                        <div class="d-flex gap-3">
                            @foreach (var size in new[] { "Small", "Medium", "Large" })
                            {
                                var s = size;
                                <div class="form-check">
                                    <input class="form-check-input" type="radio" name="fontSize" id="fs-@s"
                                           value="@s" checked="@(_appFontSize == s)"
                                           @onchange="() => _appFontSize = s" />
                                    <label class="form-check-label" for="fs-@s">@s</label>
                                </div>
                            }
                        </div>
                    </div>

                    <div class="mb-4">
                        <label class="form-label fw-semibold" for="langSelect">Language</label>
                        <select class="form-select" id="langSelect" @bind="_appLanguage" style="max-width: 250px;">
                            @foreach (var lang in _languages)
                            {
                                <option value="@lang">@lang</option>
                            }
                        </select>
                    </div>

                    <div class="form-check form-switch mb-4">
                        <input class="form-check-input" type="checkbox" id="compactMode" @bind="_appCompact" />
                        <label class="form-check-label" for="compactMode">Compact Mode</label>
                    </div>

                    <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
                        @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Save
                    </button>
                </div>
            </div>

            @* ── Live preview ── *@
            <div class="card settings-card">
                <div class="card-header">Live Preview</div>
                <div class="card-body preview-area @PreviewThemeClass()" style="@PreviewFontStyle()">
                    <div class="@(_appCompact ? "compact-preview" : "")">
                        <h5>Dashboard</h5>
                        <p>This is a preview of how your settings will look.</p>
                        <div class="d-flex gap-2 mb-2">
                            <span class="badge bg-primary">Badge</span>
                            <span class="badge bg-success">Active</span>
                        </div>
                        <button class="btn btn-sm btn-primary me-2">Primary Action</button>
                        <button class="btn btn-sm btn-outline-secondary">Secondary</button>
                    </div>
                </div>
            </div>
        </section>;
}

@code {
    // ── Section definitions ──
    private record SectionInfo(string Label, string Icon);
    private readonly Dictionary<string, SectionInfo> _sections = new()
    {
        ["profile"] = new("Profile", "👤"),
        ["notifications"] = new("Notifications", "🔔"),
        ["security"] = new("Security", "🔒"),
        ["appearance"] = new("Appearance", "🎨"),
    };

    private string ActiveSection { get; set; } = "profile";
    private bool _loading = true;
    private bool _saving;

    // ── Toast ──
    private string? _toastMessage;
    private bool _toastIsError;
    private CancellationTokenSource? _toastCts;

    // ── Profile state ──
    private UserProfile? _savedProfile;
    private string _profileDisplayName = "";
    private string _profileEmail = "";
    private string _profileAvatarUrl = "";
    private string _profileBio = "";

    // ── Notification state ──
    private bool _notifEmail;
    private bool _notifPush;
    private bool _notifWeekly;
    private HashSet<string> _mutedChannels = [];
    private readonly string[] _allChannels = ["general", "engineering", "design", "marketing", "random", "announcements"];

    // ── Security state ──
    private SecuritySettings? _securitySettings;
    private bool _twoFactorEnabled;
    private List<ActiveSession>? _sessions;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private const string _currentSessionId = "sess-1"; // treat first session as current

    // Revoke confirmation
    private bool _showRevokeConfirm;
    private ActiveSession? _revokeTarget;

    // ── Appearance state ──
    private string _appTheme = "Light";
    private string _appFontSize = "Medium";
    private string _appLanguage = "English";
    private bool _appCompact;
    private readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

    // ═══════════════ Lifecycle ═══════════════

    protected override async Task OnInitializedAsync()
    {
        await LoadSectionData("profile");
    }

    private async Task SetActiveSection(string section)
    {
        if (ActiveSection == section) return;
        ActiveSection = section;
        _loading = true;
        await LoadSectionData(section);
    }

    private async Task LoadSectionData(string section)
    {
        try
        {
            switch (section)
            {
                case "profile":
                    var profile = await SettingsService.GetProfileAsync();
                    ApplyProfile(profile);
                    _savedProfile = profile;
                    break;

                case "notifications":
                    var notifs = await SettingsService.GetNotificationPrefsAsync();
                    _notifEmail = notifs.EmailNotifications;
                    _notifPush = notifs.PushNotifications;
                    _notifWeekly = notifs.WeeklyDigest;
                    _mutedChannels = [.. notifs.MutedChannels];
                    break;

                case "security":
                    _securitySettings = await SettingsService.GetSecuritySettingsAsync();
                    _twoFactorEnabled = _securitySettings.TwoFactorEnabled;
                    _sessions = [.. _securitySettings.Sessions];
                    _currentPassword = "";
                    _newPassword = "";
                    _confirmPassword = "";
                    break;

                case "appearance":
                    var appearance = await SettingsService.GetAppearanceAsync();
                    _appTheme = appearance.Theme;
                    _appFontSize = appearance.FontSize;
                    _appLanguage = appearance.Language;
                    _appCompact = appearance.CompactMode;
                    break;
            }
        }
        finally
        {
            _loading = false;
        }
    }

    // ═══════════════ Profile ═══════════════

    private void ApplyProfile(UserProfile p)
    {
        _profileDisplayName = p.DisplayName;
        _profileEmail = p.Email;
        _profileAvatarUrl = p.AvatarUrl;
        _profileBio = p.Bio;
    }

    private async Task SaveProfile()
    {
        _saving = true;
        try
        {
            var updated = new UserProfile(_profileDisplayName, _profileEmail, _profileAvatarUrl, _profileBio);
            await SettingsService.SaveProfileAsync(updated);
            _savedProfile = updated;
            await ShowToast("Profile saved successfully.");
        }
        catch (Exception ex)
        {
            await ShowToast(ex.Message, isError: true);
        }
        finally { _saving = false; }
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
            ApplyProfile(_savedProfile);
    }

    // ═══════════════ Notifications ═══════════════

    private void ToggleMuteChannel(string channel, bool muted)
    {
        if (muted) _mutedChannels.Add(channel);
        else _mutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        _saving = true;
        try
        {
            var prefs = new NotificationPrefs(_notifEmail, _notifPush, _notifWeekly, [.. _mutedChannels]);
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            await ShowToast("Notification preferences saved.");
        }
        catch (Exception ex)
        {
            await ShowToast(ex.Message, isError: true);
        }
        finally { _saving = false; }
    }

    // ═══════════════ Security ═══════════════

    private async Task UpdatePassword()
    {
        if (_newPassword != _confirmPassword)
        {
            await ShowToast("Passwords do not match.", isError: true);
            return;
        }

        _saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _passwordPanelOpen = false;
            _securitySettings = await SettingsService.GetSecuritySettingsAsync();
            await ShowToast("Password updated successfully.");
        }
        catch (Exception ex)
        {
            await ShowToast(ex.Message, isError: true);
        }
        finally { _saving = false; }
    }

    private void RequestRevoke(ActiveSession session)
    {
        _revokeTarget = session;
        _showRevokeConfirm = true;
    }

    private void CancelRevoke()
    {
        _showRevokeConfirm = false;
        _revokeTarget = null;
    }

    private async Task ConfirmRevoke()
    {
        if (_revokeTarget is null) return;
        _saving = true;
        try
        {
            await SettingsService.RevokeSessionAsync(_revokeTarget.Id);
            _sessions = _sessions?.Where(s => s.Id != _revokeTarget.Id).ToList();
            _showRevokeConfirm = false;
            _revokeTarget = null;
            await ShowToast("Session revoked.");
        }
        catch (Exception ex)
        {
            await ShowToast(ex.Message, isError: true);
        }
        finally { _saving = false; }
    }

    // ═══════════════ Appearance ═══════════════

    private async Task SaveAppearance()
    {
        _saving = true;
        try
        {
            var settings = new AppearanceSettings(_appTheme, _appFontSize, _appLanguage, _appCompact);
            await SettingsService.SaveAppearanceAsync(settings);
            await ShowToast("Appearance settings saved.");
        }
        catch (Exception ex)
        {
            await ShowToast(ex.Message, isError: true);
        }
        finally { _saving = false; }
    }

    private string PreviewThemeClass() => _appTheme switch
    {
        "Dark" => "preview-dark",
        "System" => "preview-system",
        _ => "preview-light"
    };

    private string PreviewFontStyle() => _appFontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 1rem;"
    };

    // ═══════════════ Helpers ═══════════════

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }

    private async Task ShowToast(string message, bool isError = false)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;

        _toastMessage = message;
        _toastIsError = isError;
        StateHasChanged();

        try
        {
            await Task.Delay(3000, token);
            _toastMessage = null;
            StateHasChanged();
        }
        catch (TaskCanceledException) { }
    }
}

